document_no = #{documentNo}, document_no_id = #{documentNoId}, business_type = #{businessType}, customer_id = #{customerId}, document_status = #{documentStatus}, contract_type = #{contractType}, application_type = #{applicationType}, applicant = #{applicant}, application_date = #{applicationDate}, application_status = #{applicationStatus}, approved = #{approved}, approved_date = #{approvedDate}, approved_status = #{approvedStatus}, approved_comments = #{approvedComments}, remark = #{remark},
